python3 -c "
import json
with open('C:/Users/math_/.claude/skills/survey-search/data/catalogue.json', 'r', encoding='utf-8') as f:
    cat = json.load(f)

# Find surveys for each key variable
vars_to_find = {
    'pol_behav_3': 'Posted political views on SM',
    'pol_speech_2': 'Comfort responding to disagreeable posts', 
    'pol_speech_3': 'Comfort expressing opinions at work/school',
}

# Also need gender identity: gender1 (with NB option) or transgender question
# Let's find all appearances

surveys_by_var = {}
for key, q in cat['questions'].items():
    for app in q.get('appearances', []):
        var = app.get('variable', '')
        survey = app['survey']
        if var in vars_to_find:
            surveys_by_var.setdefault(var, set()).add(survey)

# Gender identity vars
for key, q in cat['questions'].items():
    for app in q.get('appearances', []):
        var = app.get('variable', '')
        survey = app['survey']
        # gender1 with NB option or transgender question
        if var in ('gender1', 'gender2'):
            surveys_by_var.setdefault('gender_id', set()).add(survey)

# Also check the older transgender question
for key in ['q_are_you_transgender', 'q_do_you_consider_yourself_to_be_transgender']:
    if key in cat['questions']:
        for app in cat['questions'][key]['appearances']:
            surveys_by_var.setdefault('transgender_q', set()).add(app['survey'])

for var, surveys in surveys_by_var.items():
    print(f'{var}: {len(surveys)} surveys')

# Find intersection
gender_surveys = surveys_by_var.get('gender_id', set()) | surveys_by_var.get('transgender_q', set())
pol_surveys = surveys_by_var.get('pol_behav_3', set()) & surveys_by_var.get('pol_speech_2', set()) & surveys_by_var.get('pol_speech_3', set())
common = gender_surveys & pol_surveys
print(f'\nSurveys with ALL pol expression vars AND gender identity: {len(common)}')
for s in sorted(common):
    print(f'  {s}')
" 2>&1

